for lang, add in DATA.items():
    path = f"{lang}.json"
    with open(path) as f:
        data = json.load(f, object_pairs_hook=collections.OrderedDict)
    data.setdefault("landing", {})
    data["landing"].update(add)
    with open(path, "w") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
        f.write("\n")

